{:version=>3, :sections=>[{:offset=>{:line=>0, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/game_system/TheIndieHack.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module GameSystem\n    class TheIndieHack < Base\n      # ゲームシステムの識別子\n      ID = 'TheIndieHack'\n\n      # ゲームシステム名\n      NAME = 'The Indie Hack'\n\n      # ゲームシステム名の読みがな\n      SORT_KEY = 'しいんていはつく'\n\n      # ダイスボットの使い方\n      HELP_MESSAGE = <<~INFO_MESSAGETEXT\n        ■判定　cIH+a        c:CL  a:能力値\n\n        例)IH: ライトダイスとダークダイスを1個ずつ振って、その結果を表示\n      INFO_MESSAGETEXT\n\n      register_prefix('([+-]?\\d)?IH')\n\n      def eval_game_system_specific_command(command)\n        resolute_action(command)\n      end\n\n      private\n\n      # ダイス判定\n      # @param [String] command\n      # @return [Result]\n      def resolute_action(command)\n        m = /([+-]?\\d)?IH([+-]\\d)?/.match(command)\n        return nil unless m\n\n        cl = m[1].to_i\n        abilities = m[2].to_i\n\n        dices = @randomizer.roll_barabara(2, 6)\n        dice_text = dices.join(\",\")\n        dices[0] += cl\n        dices[1] += abilities\n        dice_text2 = dices.join(\",\")\n        diff = dices[1] - dices[0]\n        side = diff < 0 ? \"ライト\" : \"ダーク\"\n        side = \"両\" if diff == 0\n        if dice_text == dice_text2\n          output = \"(IH) ＞ \#{dice_text} ＞ \#{side}\#{get_success_level(diff)}\"\n        else\n          output = \"(\#{m[1]}IH\#{m[2]}) ＞ [\#{dice_text}] ＞ \#{dice_text2} ＞ \#{side}\#{get_success_level(diff)}\"\n        end\n        if diff > 0\n          return Result.success(output)\n        elsif diff < 0\n          return Result.failure(output)\n        else\n          return Result.new.tap do |result|\n            result.text = output\n          end\n        end\n      end\n\n      def get_success_level(die_difference)\n        case die_difference.abs\n        when 0\n          return \"陣営がそれぞれ確定描写を1つ追加します\"\n        when 1\n          return \"陣営が確定描写を1つ追加しますが、味方によって追加されたネガティブな確定描写を1つ受けます\"\n        when 2\n          return \"陣営が確定描写を1つ追加します\"\n        when 3\n          return \"陣営が確定描写を1つ追加し、さらに場面描写を1つ追加します\"\n        when 4\n          return \"陣営が確定描写を1つ追加し、さらにその陣営の味方ひとりも確定描写を1つ追加します\"\n        else\n          return \"陣営が確定描写を2つ追加します\"\n        end\n      end\n    end\n  end\nend\n"], :names=>["<main>", "<module:BCDice>", "<module:GameSystem>", "<class:TheIndieHack>", "self", "register_prefix", "eval_game_system_specific_command", "command", "resolute_action", "private", "m", "match", "cl", "[]", "1", "to_i", "abilities", "2", "dices", "@randomizer", "roll_barabara", "6", "dice_text", "join", "[]=", "0", "+", "dice_text2", "diff", "-", "side", "<", "output", "get_success_level", ">", "Result", "success", "failure", "tap", "new", "block in resolute_action", "result", "block (2 levels) in resolute_action", "text=", "die_difference", "abs", "3", "4", "Base"], :mappings=>"AAAAA,2BAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;AAAAA;;QAEE,8BAAKA,cAAL;QAGA,gCAAOA,gBAAP;QAGA,oCAAWA,UAAX;QAGA,wCACNA,gCADqB,GAErBA,IAFqB,GAGrBA,uCAHM;QAMAC,IAAAC,iBAAAA,CAAgBF,eAAhBE;;AAEAC,QAAAA,iDAAAA,6CAAsCC,OAAtCD;AAAAA,UAAAA;;UACEA,OAAAF,IAAAI,iBAAAA,CAAgBD,OAAhBC;QADFF,CAAAA;QAIAF,IAAAK,SAAAA,CAAAA;;AAKAD,QAAAA,+BAAAA,2BAAoBD,OAApBC;AAAAA,UAAAA;;;UACEE,IAAI,uBAAuBC,OAAAA,CAAOJ,OAAPI;UAC3B,KAAA,QAAkBD,CAAlB,CAAA;YAAA,OAAO;UAAP;UAEAE,KAAKF,CAACG,OAAAA,CAACC,CAADD,CAAGE,MAAAA,CAAAA;UACTC,YAAYN,CAACG,OAAAA,CAACI,CAADJ,CAAGE,MAAAA,CAAAA;UAEhBG,QAAQC,eAAWC,eAAAA,CAAeH,CAA1B,EAA6BI,CAAlBD;UACnBE,YAAYJ,KAAKK,MAAAA,CAAMf,GAANe;UACjBL,KAAKM,QAAAA,CAACC,CAAN,EAAKC,SAALR,KAAKL,OAAAA,CAACY,CAADZ,CAAAa,EAAOd,EAAPc,CAAAF;UACLN,KAAKM,QAAAA,CAACV,CAAN,EAAKY,SAALR,KAAKL,OAAAA,CAACC,CAADD,CAAAa,EAAOV,SAAPU,CAAAF;UACLG,aAAaT,KAAKK,MAAAA,CAAMf,GAANe;UAClBK,OAAgBC,UAATX,KAAKL,OAAAA,CAACC,CAADD,CAAIgB,EAAEX,KAAKL,OAAAA,CAACY,CAADZ,CAAPgB;UAChBC,OAAO,CAAA,QAAKC,OAALH,IAAKG,EAAEN,CAAFM,CAAL,CAAA,GAAA,CAAW